VALUES
  ('social-worker-moex-04010', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會工作專業注入很多心血服務處於低社經地位家庭的兒少，而社會工作者和生活在貧窮家 庭兒少工作時，社會工作者應考量許多的層面，下列敘述何者正確？', '["先關注兒少是否吃飽，其他的就依機構的專業能力決定是否服務", "社會工作者可運用兒少同儕協助處理家庭的議題", "社會工作者應先盤點機構資源，確立資源足夠之後才進行開案評估", "社會工作者須從「人在情境中」的架構，評估環境中潛在的問題，以掌握兒少生活中可能 導致其發展的問題層面"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04011', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於系統理論相關概念的敘述，下列何者正確？', '["系統是區分一個實體的邊界或邊緣", "動態均衡指系統維持相對穩定，一旦平衡破壞會自我調整回復穩定的傾向", "角色是個體在社會結構中所占據的位置", "投入指系統對所接收到的各種能量的回應，它會影響環境中其它系統"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04012', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關社會工作者應用生態系統論的敘述，下列何者錯誤？', '["它有助我們檢視環境的能力以及提升服務的效能", "它可以引導我們確認相關系統、次系統和高層系統的概念", "它有助我們分析個體生活空間中衝突與支持力量的交互作用", "它是我們瞭解社會系統唯一的概念架構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04013', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '①經濟制度的失功能  ②階級不平等造成的財富分配不均  ③不良鄰里互動中所學到的自我 挫敗感。上述三種貧窮看法相對應的理論觀點，下列組合何者正確？', '["", "社會衝突論", "結構功能論", "文化中心論"]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04014', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '親職化（parentification）是描述親子間的親職角色扮演。下列關於親職化的敘述，何者正確？', '["孩子與父母的角色反轉", "只出現在離婚家庭的孩子", "孩子不會覺得有壓力", "是孩子的正常發展任務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04015', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '布朗芬布倫納（Bronfenbrenner）生態系統論（ecologicaltheory）中，著眼說明不同世代間之 個體受社會變遷所影響而有不同態度與價值，屬於下列那項系統？', '["中間（mesosystem）", "外部（exosystem）", "微視（microsystem）", "年代（chronosystem）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04016', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Newman和Newman指出個體性別概念的理解與發展分為四個階段：階段一、正確使用性別 標誌；階段二、理解性別是穩定的；階段三、理解性別是恒定的；階段四、性別是有生殖器 官基礎的。學齡兒童的性別發展與認同所處階段，下列選項何者正確？', '["階段一與階段二", "階段二與階段三", "階段三與階段四", "僅在階段四"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04017', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Forward（1989）所稱的有毒父母是指父母在不知不覺中傷害自己的子女。下列何者不是 Forward所稱的有毒父母的特徵？', '["主宰慾強的父母", "吸毒的父母", "無法勝任教養子女的父母", "身體、精神或性虐待者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04018', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關婦女懷孕期間，下列敘述何者錯誤？', '["胎兒酒精症候群是胎兒的母親在懷孕期間攝取酒精對胎兒造成影響", "孕婦在懷孕期間嚴重酗酒會導致嬰兒不尋常的臉部特徵", "懷孕期間飲酒對胎兒不會有影響", "胎兒損傷的嚴重程度隨著懷孕期間酒精的攝取量而增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
